INSERT INTO `requests` (`id`, `title`, `note`, `manager_group`, `priority`, `manager_name`, `attachment_url`, `status`, `is_draft`, `created_by_user_id`, `created_at`, `updated_at`) VALUES
(1, 'Yêu cầu sửa chữa máy lạnh phòng A101', 'Máy lạnh tại phòng A101 bị hỏng máy nén - không làm lạnh được. Đề nghị kiểm tra và sửa chữa gấp.', 'CSVC', 'HIGH', 'Nguyễn Minh Tuấn', NULL, 'NEW', 0, 1, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(2, 'Yêu cầu cấp máy tính cho phòng LAB_CNTT02', 'Phòng máy tính LAB_CNTT02 hiện có 10 máy hỏng cần thay thế. Đề nghị cấp bổ sung 10 máy tính mới.', 'CNTT', 'HIGH', 'Bùi Thị Hồng Nhung', NULL, 'IN_PROGRESS', 0, 7, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(3, 'Yêu cầu thay bóng đèn hành lang tòa A', 'Hệ thống đèn hành lang tầng 2 và tầng 3 tòa A bị hỏng nhiều bóng. Đề nghị thay thế toàn bộ.', 'CSVC', 'NORMAL', 'Trần Thị Lan Anh', NULL, 'RESOLVED', 0, 4, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(4, 'Yêu cầu bổ sung bàn ghế phòng B202', 'Phòng B202 hiện thiếu 10 bộ bàn ghế do số lượng sinh viên tăng. Đề nghị bổ sung sớm.', 'CSVC', 'NORMAL', 'Hoàng Văn Bình', NULL, 'DRAFT', 1, 8, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(5, 'Yêu cầu sửa chữa máy chiếu phòng A201', 'Máy chiếu tại phòng A201 bị lỗi không hiển thị hình ảnh. Giảng viên phản ánh ảnh hưởng đến giảng dạy.', 'CNTT', 'HIGH', 'Bùi Thị Hồng Nhung', NULL, 'NEW', 0, 7, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(6, 'Yêu cầu vệ sinh điều hòa các phòng tòa B', 'Điều hòa các phòng tòa B chưa được vệ sinh trong học kỳ này. Đề nghị lên kế hoạch vệ sinh định kỳ.', 'CSVC', 'NORMAL', 'Trần Thị Lan Anh', NULL, 'IN_PROGRESS', 0, 4, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(7, 'Yêu cầu sửa chữa bảng trắng phòng A103', 'Bảng trắng phòng A103 bị bong lớp phủ không thể xóa sạch. Đề nghị thay mới hoặc phủ lại bề mặt.', 'CSVC', 'LOW', 'Trần Thị Lan Anh', NULL, 'RESOLVED', 0, 4, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(8, 'Yêu cầu cấp phát dụng cụ cho xưởng cơ khí', 'Xưởng LAB_CK01 thiếu bộ dụng cụ cơ bản cho sinh viên thực hành. Đề nghị cấp bổ sung theo danh sách đính kèm.', 'THIET_BI', 'HIGH', 'Nguyễn Đức Thắng', NULL, 'DRAFT', 1, 6, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(9, 'Yêu cầu sửa chữa hệ thống loa phòng B301', 'Loa phòng B301 phát ra tiếng rè không rõ. Ảnh hưởng đến chất lượng nghe giảng của sinh viên.', 'CSVC', 'NORMAL', 'Đặng Thị Thu Hằng', NULL, 'NEW', 0, 9, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(10, 'Yêu cầu nâng cấp mạng LAN phòng LAB_CNTT01', 'Hạ tầng mạng LAB_CNTT01 cũ kỹ, tốc độ chậm. Đề nghị nâng cấp hệ thống switch và dây cáp mạng.', 'CNTT', 'HIGH', 'Bùi Thị Hồng Nhung', NULL, 'IN_PROGRESS', 0, 7, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(11, 'Yêu cầu thay kính cửa phòng A302', 'Kính cửa phòng A302 bị nứt vỡ do va đập. Đề nghị thay thế để đảm bảo an toàn.', 'CSVC', 'HIGH', 'Đặng Thị Thu Hằng', NULL, 'RESOLVED', 0, 4, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(12, 'Yêu cầu bảo trì máy móc xưởng ô tô', 'Thiết bị tại LAB_KTOTO01 và LAB_KTOTO02 cần được bảo dưỡng định kỳ trước đầu học kỳ mới.', 'THIET_BI', 'NORMAL', 'Phan Minh Khoa', NULL, 'DRAFT', 1, 10, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(13, 'Yêu cầu sửa chữa toilet tầng 2 tòa A', 'Toilet tầng 2 tòa A có 2 bồn cầu hỏng và hệ thống xả nước không hoạt động. Đề nghị sửa chữa gấp.', 'CSVC', 'HIGH', 'Trần Thị Lan Anh', NULL, 'NEW', 0, 4, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(14, 'Yêu cầu cấp mực in cho văn phòng khoa', 'Văn phòng Khoa Công nghệ Thông tin hết mực in. Đề nghị cấp bổ sung 5 hộp mực HP.', 'CNTT', 'NORMAL', 'Bùi Thị Hồng Nhung', NULL, 'IN_PROGRESS', 0, 7, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(15, 'Yêu cầu sửa chữa rèm cửa phòng C101', 'Rèm cửa phòng C101 bị đứt dây kéo, không điều chỉnh được. Ảnh hưởng đến ánh sáng phòng học.', 'CSVC', 'LOW', 'Trần Thị Lan Anh', NULL, 'RESOLVED', 0, 4, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(16, 'Yêu cầu lắp đặt camera an ninh khu vực xưởng', 'Khu vực xưởng cơ khí và xưởng ô tô chưa có camera giám sát. Đề nghị lắp đặt để đảm bảo an ninh.', 'CSVC', 'NORMAL', 'Nguyễn Minh Tuấn', NULL, 'DRAFT', 1, 1, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(17, 'Yêu cầu sửa chữa thang máy tòa B', 'Thang máy tòa B thường xuyên bị lỗi, dừng giữa chừng. Đề nghị bảo trì khẩn cấp.', 'CSVC', 'HIGH', 'Trần Thị Lan Anh', NULL, 'NEW', 0, 4, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(18, 'Yêu cầu cấp thiết bị bảo hộ cho sinh viên thực hành', 'Sinh viên thực hành tại xưởng thiếu kính bảo hộ và găng tay. Đề nghị cấp đủ số lượng.', 'THIET_BI', 'HIGH', 'Nguyễn Đức Thắng', NULL, 'IN_PROGRESS', 0, 6, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(19, 'Yêu cầu sơn lại phòng học B103', 'Phòng B103 tường bị ố vàng, bong tróc sơn. Đề nghị sơn lại trước khai giảng năm học mới.', 'CSVC', 'NORMAL', 'Trần Thị Lan Anh', NULL, 'RESOLVED', 0, 4, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(20, 'Yêu cầu thay thế máy tính hỏng phòng D201', '3 máy tính trong phòng D201 không khởi động được. Đề nghị sửa chữa hoặc thay thế mới.', 'CNTT', 'NORMAL', 'Đặng Thị Thu Hằng', NULL, 'DRAFT', 1, 9, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(21, 'Yêu cầu bảo trì hệ thống điện xưởng LAB_KTD01', 'Hệ thống điện xưởng LAB_KTD01 xuất hiện sự cố chập chờn. Cần kiểm tra và bảo trì ngay.', 'THIET_BI', 'HIGH', 'Đặng Thị Thu Hằng', NULL, 'NEW', 0, 9, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(22, 'Yêu cầu cấp bảng vẽ kỹ thuật phòng C103', 'Phòng vẽ C103 thiếu 5 bảng vẽ kỹ thuật cho sinh viên. Đề nghị bổ sung trước tuần 3 của học kỳ.', 'THIET_BI', 'NORMAL', 'Hoàng Văn Bình', NULL, 'IN_PROGRESS', 0, 8, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(23, 'Yêu cầu sửa chữa hệ thống chiếu sáng xưởng', 'Đèn tại LAB_CK01 và LAB_CK02 bị hỏng một số bóng. Ảnh hưởng đến an toàn khi thực hành.', 'CSVC', 'HIGH', 'Nguyễn Đức Thắng', NULL, 'RESOLVED', 0, 6, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(24, 'Yêu cầu thanh lý tài sản hỏng học kỳ I/2024', 'Danh sách tài sản hỏng không sửa được cần được lập hồ sơ thanh lý theo quy định. Đính kèm danh sách.', 'THIET_BI', 'NORMAL', 'Nguyễn Minh Tuấn', NULL, 'DRAFT', 1, 1, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(25, 'Yêu cầu cấp mô hình học cụ cho Khoa Ô tô', 'Khoa Kỹ thuật Ô tô cần bổ sung mô hình động cơ mới phục vụ đào tạo học kỳ II.', 'THIET_BI', 'HIGH', 'Phan Minh Khoa', NULL, 'NEW', 0, 10, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(26, 'Yêu cầu sửa chữa cửa phòng LAB_XD01', 'Cửa phòng LAB_XD01 bị hỏng bản lề, không đóng kín. Ảnh hưởng đến bảo mật thiết bị trong phòng.', 'CSVC', 'NORMAL', 'Hoàng Văn Bình', NULL, 'IN_PROGRESS', 0, 8, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(27, 'Yêu cầu vệ sinh máy tính phòng LAB_CNTT02', 'Máy tính phòng LAB_CNTT02 bụi bẩn, cần vệ sinh định kỳ để đảm bảo tuổi thọ thiết bị.', 'CNTT', 'LOW', 'Bùi Thị Hồng Nhung', NULL, 'RESOLVED', 0, 7, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(28, 'Yêu cầu lắp thêm ổ cắm điện phòng C201', 'Phòng C201 thiếu ổ cắm điện cho sinh viên sạc thiết bị trong giờ thực hành. Đề nghị lắp bổ sung.', 'CSVC', 'NORMAL', 'Đặng Thị Thu Hằng', NULL, 'DRAFT', 1, 9, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(29, 'Yêu cầu sửa chữa hàng rào khu vực xưởng', 'Hàng rào khu vực xưởng có đoạn bị gãy đổ. Cần sửa chữa để đảm bảo an toàn và bảo vệ tài sản.', 'CSVC', 'HIGH', 'Trần Thị Lan Anh', NULL, 'NEW', 0, 4, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(30, 'Yêu cầu nâng cấp phần mềm máy tính LAB_CNTT01', 'Phần mềm chuyên ngành trên máy tính LAB_CNTT01 đã cũ cần cập nhật phiên bản mới.', 'CNTT', 'NORMAL', 'Bùi Thị Hồng Nhung', NULL, 'IN_PROGRESS', 0, 7, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(31, 'Yêu cầu sửa chữa máy chiếu phòng B101', 'Máy chiếu phòng B101 không lấy nét được, hình ảnh bị mờ. Cần sửa chữa trước khi giảng dạy học kỳ mới.', 'THIET_BI', 'NORMAL', 'Nguyễn Đức Thắng', NULL, 'RESOLVED', 0, 6, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(32, 'Yêu cầu cấp dụng cụ vệ sinh cho các phòng học', 'Các phòng học tòa A và tòa B thiếu dụng cụ vệ sinh cơ bản. Đề nghị cấp bổ sung theo số phòng.', 'CSVC', 'LOW', 'Trần Thị Lan Anh', NULL, 'DRAFT', 1, 4, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(33, 'Yêu cầu kiểm tra và bảo dưỡng máy bơm nước', 'Hệ thống máy bơm nước tòa C hoạt động không ổn định. Cần kiểm tra và bảo dưỡng định kỳ.', 'CSVC', 'HIGH', 'Trần Thị Lan Anh', NULL, 'NEW', 0, 4, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(34, 'Yêu cầu cấp bổ sung ghế cho hội trường', 'Hội trường thiếu 30 ghế cho các sự kiện lớn của trường. Đề nghị mua bổ sung hoặc mượn từ kho.', 'CSVC', 'NORMAL', 'Nguyễn Minh Tuấn', NULL, 'IN_PROGRESS', 0, 1, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(35, 'Yêu cầu sửa chữa loa treo tường phòng B302', 'Loa phòng B302 phát ra tiếng lạch cạch, âm thanh không rõ. Ảnh hưởng đến chất lượng giảng dạy.', 'THIET_BI', 'NORMAL', 'Đặng Thị Thu Hằng', NULL, 'RESOLVED', 0, 9, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(36, 'Yêu cầu cấp thiết bị đo lường cho LAB_KTD02', 'Xưởng LAB_KTD02 thiếu đồng hồ vạn năng và thiết bị đo lường điện cho sinh viên thực hành.', 'THIET_BI', 'HIGH', 'Đặng Thị Thu Hằng', NULL, 'DRAFT', 1, 9, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(37, 'Yêu cầu sửa chữa ổ khóa văn phòng khoa CK', 'Ổ khóa văn phòng Khoa Cơ khí bị hỏng không mở được. Đề nghị thay khóa mới ngay.', 'CSVC', 'HIGH', 'Nguyễn Đức Thắng', NULL, 'NEW', 0, 6, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(38, 'Yêu cầu vệ sinh bể nước mái tòa A', 'Bể nước mái tòa A chưa được vệ sinh trong 6 tháng. Đề nghị vệ sinh định kỳ theo quy định.', 'CSVC', 'NORMAL', 'Trần Thị Lan Anh', NULL, 'IN_PROGRESS', 0, 4, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(39, 'Yêu cầu sửa chữa bộ mô phỏng ô tô LAB_KTOTO01', 'Bộ mô phỏng ô tô số 1 tại LAB_KTOTO01 bị lỗi phần mềm, không khởi động được. Đề nghị liên hệ nhà cung cấp sửa chữa.', 'THIET_BI', 'HIGH', 'Phan Minh Khoa', NULL, 'RESOLVED', 0, 10, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(40, 'Yêu cầu trang bị biển số phòng mới tòa D', 'Tòa D mới chưa có biển số phòng. Đề nghị làm biển số đồng bộ với các tòa còn lại.', 'CSVC', 'LOW', 'Trần Thị Lan Anh', NULL, 'DRAFT', 1, 4, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(41, 'Yêu cầu cấp máy in cho văn phòng Khoa XD', 'Máy in văn phòng Khoa Xây dựng bị hỏng không sửa được. Đề nghị mua thay thế mới.', 'CNTT', 'NORMAL', 'Hoàng Văn Bình', NULL, 'NEW', 0, 8, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(42, 'Yêu cầu sửa chữa mô hình động cơ diesel LAB_CK01', 'Mô hình động cơ diesel tại LAB_CK01 bị hỏng hệ thống nhiên liệu. Cần sửa chữa trước học kỳ II.', 'THIET_BI', 'HIGH', 'Nguyễn Đức Thắng', NULL, 'IN_PROGRESS', 0, 6, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(43, 'Yêu cầu lắp đặt wifi cho phòng D202', 'Phòng D202 chưa có wifi nên sinh viên không thể học trực tuyến. Đề nghị lắp đặt access point.', 'CNTT', 'NORMAL', 'Trần Thị Lan Anh', NULL, 'RESOLVED', 0, 4, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(44, 'Yêu cầu cấp bổ sung bàn vẽ kỹ thuật', 'Phòng vẽ D102 thiếu 5 bàn vẽ kỹ thuật cho sinh viên năm nhất Khoa Xây dựng. Đề nghị cấp gấp.', 'THIET_BI', 'HIGH', 'Hoàng Văn Bình', NULL, 'DRAFT', 1, 8, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(45, 'Yêu cầu thay thế switch mạng VP_CNTT', 'Switch mạng phòng VP_CNTT bị lỗi, không ổn định. Đề nghị thay thế để đảm bảo kết nối mạng.', 'CNTT', 'HIGH', 'Võ Hoàng Nam', NULL, 'NEW', 0, 5, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(46, 'Yêu cầu sơn kẻ đường đi trong khuôn viên', 'Đường đi bộ và kẻ vạch đỗ xe trong khuôn viên bị mờ. Đề nghị kẻ lại để đảm bảo an toàn.', 'CSVC', 'NORMAL', 'Trần Thị Lan Anh', NULL, 'IN_PROGRESS', 0, 4, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(47, 'Yêu cầu sửa chữa màn chiếu điện phòng C201', 'Màn chiếu điện phòng C201 bị hỏng motor, không cuộn lên được. Đề nghị sửa chữa hoặc thay mới.', 'THIET_BI', 'NORMAL', 'Đặng Thị Thu Hằng', NULL, 'RESOLVED', 0, 9, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(48, 'Yêu cầu kiểm tra hệ thống PCCC toàn trường', 'Hệ thống phòng cháy chữa cháy cần được kiểm tra định kỳ 6 tháng/lần. Đề nghị lên kế hoạch kiểm tra.', 'CSVC', 'HIGH', 'Nguyễn Minh Tuấn', NULL, 'DRAFT', 1, 1, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(49, 'Yêu cầu cấp bổ sung ghế xoay cho LAB_CK02', 'Xưởng LAB_CK02 thiếu 8 ghế xoay cho sinh viên ngồi thực hành lý thuyết tại chỗ.', 'THIET_BI', 'NORMAL', 'Nguyễn Đức Thắng', NULL, 'NEW', 0, 6, '2026-05-12 07:31:56', '2026-05-12 07:31:56'),
(50, 'Yêu cầu sửa chữa hệ thống chiếu sáng sân trường', 'Một số đèn chiếu sáng sân trường bị hỏng, gây mất an toàn vào ban đêm. Đề nghị thay thế gấp.', 'CSVC', 'HIGH', 'Trần Thị Lan Anh', NULL, 'IN_PROGRESS', 0, 4, '2026-05-12 07:31:56', '2026-05-12 07:31:56');
